/* ── Runner ──────────────────────────────────────────────────────────────────── */
async function run() {
  await mongoose.connect(process.env.MONGO_URI);
  let upserts = 0;
  for (const q of questions) {
    await Question.updateOne({ questionId: q.questionId }, { $set: q }, { upsert: true });
    upserts++;
  }
  console.log(`✓ Layer A: ${upserts}/${questions.length} ICSE Math 10 questions upserted.`);
  await mongoose.disconnect();
}

run().catch((err) => { console.error(err); process.exit(1); });
